@using NonFactors.Mvc.Grid;
@using System.Data;
@using System.Data.SqlClient;
@using System;


@model Firstronic.Core.Entities.App.Engineering.tbl_CS_idt_partnumbers_FULL

@{
  bool isNew = !(Model != null && !String.IsNullOrEmpty(Model.PartNumber));

  var customerlist = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery(@"SELECT [CustomerID],[CustomerName] FROM [CS_idt_external_customers] Order by CustomerName asc");

  var parttypelist = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery("SELECT [Part_Type_ID] ,[Part_Type] FROM [Part_Type]");
  var Typelist = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery("SELECT [TypeID] ,[Type] FROM [SP_tbl_layers_extra_Type]");
  var DocTypelist = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery("SELECT TOP (1000) [AutoID],[DocType] FROM [EN_tbl_visualAids_DocType]");


  var FacilityList = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery("SELECT [Facility_Key],[Facility_Name] FROM [Common_Facilities]");

  var today = DateTime.Now;

  SqlParameter[] idParameters = new SqlParameter[]{
        new SqlParameter("@PartID",SqlDbType.Int){Value = Model.PartID}
   };
}

@section head{
  <style nonce="@Html.ScriptNonce()">
    .arrow-1 {
      width:100px;
      height:30px;
      display: flex;
    }
    .arrow-1:before {
      content: "";
      background: currentColor;
      width:15px;
      clip-path: polygon(0 10px,calc(100% - 15px) 10px,calc(100% - 15px) 0,100% 50%,calc(100% - 15px) 100%,calc(100% - 15px) calc(100% - 10px),0 calc(100% - 10px));
      animation: a1 1.5s infinite linear;
    }
    @@keyframes a1 {
      90%,100%{flex-grow: 1}
    }
  </style>
}

<div class="md-card">
  <div class="md-card-toolbar">
    <h3 class="md-card-toolbar-heading-text"> Manage Part Number: @Model.PartNumber </h3>
  </div>
  <div class="md-card-content">
    @using (Html.BeginForm())
    {
      @Html.AntiForgeryToken()
      @Html.ValidationSummary("", new { @class = "hide" })

      @Html.HiddenFor(y => y.PartID, new { @id = "txtPartID" })
      @Html.HiddenFor(y => y.PartSerialFormat_OLD)

    <ul class="uk-tab" data-uk-switcher="{connect:'#tabs_4'}">
      <li class="uk-active" aria-expanded="true"><a href="#">General</a></li>
      <li class="" aria-expanded="false"><a href="#">Image</a></li>
      <li class="" aria-expanded="false"><a href="#">Serialization</a></li>
      <li class="" aria-expanded="false"><a href="#">Tools Validation</a></li>
      <li class="" aria-expanded="false"><a href="#">Packout Options</a></li>
      <li class="" aria-expanded="false"><a href="#">Areas by Panel</a></li>
      <li class="" aria-expanded="false"><a href="#">Areas with Gages</a></li>
      <li class="" aria-expanded="false"><a href="#">Areas formats</a></li>
      <li class="" aria-expanded="false"><a href="#">Areas with Pallets</a></li>
      <li class="" aria-expanded="false"><a href="#">Areas Locks</a></li>
      <li class="" aria-expanded="false"><a href="#">MergeAt</a></li>
      <li class="" aria-expanded="false"><a href="#">2 min defects</a></li>
      <li class="" aria-expanded="false"><a href="#">Custom Defects</a></li>
      <li class="" aria-expanded="false"><a href="#">Row Label Test</a></li>
      <li class="" aria-expanded="false"><a href="#">Reprint Options Validation</a></li>
      <li class="" aria-expanded="false"><a href="#">Labels Shipping Validation</a></li>
      <li class="" aria-expanded="false"><a href="#">Labels Packout Validation</a></li>
      <li class="" aria-expanded="false"><a href="#">BOM</a></li>
      <li class="" aria-expanded="false"><a href="#">Print Options</a></li>
      <li class="" aria-expanded="false"><a href="#">Packout Alternate</a></li>
      <li class="" aria-expanded="false"><a href="#">Approved Stations</a></li>
      <li class="" aria-expanded="false"><a href="#">Parameters Stations</a></li>
      @*<li class="" aria-expanded="false"><a href="#">WAVE Second Label</a></li>*@
      <li class="" aria-expanded="false"><a href="#">Routing</a></li>
      <li class="" aria-expanded="false"><a href="#">Rates</a></li>
      <li class="" aria-expanded="false"><a href="#">Assembly Instructions</a></li>
      <li class="" aria-expanded="false"><a href="#">Groups</a></li>
      <li class="" aria-expanded="false"><a href="#">Bins</a></li>
      <li class="" aria-expanded="false"><a href="#">Group-Bins</a></li>
      <li class="" aria-expanded="false"><a href="#">Printers</a></li>
      <li class="" aria-expanded="false"><a href="#">Force AOI</a></li>
      <li class="" aria-expanded="false"><a href="#">SearchAOI</a></li>
      <li class="" aria-expanded="false"><a href="#">SearchSPI</a></li>
      <li class="" aria-expanded="false"><a href="#">Configuration Keyence</a></li>
      <li class="" aria-expanded="false"><a href="#">Serialization Order</a></li>
      <li class="" aria-expanded="false"><a href="#">Max Scans</a></li>
      <li class="" aria-expanded="false"><a href="#">Packout Print Plex</a></li>
      <li class="" aria-expanded="false"><a href="#">Packout TCP/IP</a></li>
      <li class="" aria-expanded="false"><a href="#">Merge in AOI</a></li>
      <li class="" aria-expanded="false"><a href="#">Interplant</a></li>
      <li class="" aria-expanded="false"><a href="#">Areas TCP</a></li>
      <li class="" aria-expanded="false"><a href="#">SMB Paths</a></li>
      <li class="" aria-expanded="false"><a href="#">Laser Skip</a></li>
    </ul>

    <ul id="tabs_4" class="uk-switcher uk-margin">
      @*-------------------------------------------------------------------------------------------GENERAL----------*@
      <li aria-hidden="false" class="uk-active">
        <div class="uk-grid">
          <div class="uk-width-1-1">
            <p class="request-info">General information about partnumbers.</p>
          </div>
        </div>
        <div class="uk-grid" uk-grid>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.PartNumber)
              @{ if (!isNew)
                {
                  @Html.TextBoxFor(y => y.PartNumber, new { @class = "md-input", @readonly = "readonly" })
                }
                else
                {
                  @Html.TextBoxFor(y => y.PartNumber, new { @class = "md-input" })
                }
              }
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.Part_Type_ID)
              @Html.DropDownListFor(y => y.Part_Type_ID, (IEnumerable<SelectListItem>)parttypelist, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.Part_key, new { @class = "m-0 fs-14" })
              @Html.TextBoxFor(y => y.Part_key, new { @class = "md-input", ReadOnly = "True", @id = "txtPartKeyID" })
            </div>
          </div>
        </div>
        <div class="input-group mb-3">
          @Html.LabelFor(y => y.PartDesc, new { @class = "m-0 fs-14" })
          @Html.TextBoxFor(y => y.PartDesc, new { @class = "md-input" })
        </div>
        <div class="uk-grid">
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.Facility_Name, new { @class = "m-0 fs-14" })
              @Html.DropDownListFor(y => y.Facility_Key, (IEnumerable<SelectListItem>)FacilityList, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.CustomerID, new { @class = "m-0 fs-14" })
              @Html.DropDownListFor(y => y.CustomerID, (IEnumerable<SelectListItem>)customerlist, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.IsActive, new { @class = "m-0 fs-14" })
              @Html.DropDownListFor(y => y.IsActive, (IEnumerable<SelectListItem>)Model.IsActive_List, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.IsCritical, new { @class = "m-0 fs-14" })
              @Html.DropDownListFor(y => y.IsCritical, (IEnumerable<SelectListItem>)Model.IsCritical_List, new { @class = "md-input" })
            </div>
          </div>
        </div>
      </li>
      @*-------------------------------------------------------------------------------------------IMAGE----------*@
      <li aria-hidden="true">
        <div class="uk-grid">
          <div class="uk-width-1-1">
            <p class="request-info">Part Number picture.</p>
          </div>
        </div>
        @{

          var picturename = Firstronic.Framework.Queries.GetStringFromQuery("SELECT  [ImageURL] FROM  [CS_idt_partnumbers] WHERE Partid=@PartID", idParameters).Replace("[img]", "").Replace("[/img]", "");

          if (picturename != "")
          {
            <div class="input-group mb-3">
              <img id='theImg' src="@Html.Raw(Path.Combine("/UploadedFiles/PartNumbers/Pictures/", picturename))" class="img-element" width="600" height="480" />
            </div>
          }
        }

        <div class="input-group mb-3 mn-t-20">
          @Html.Label("Attachment", new { @class = "m-0 fs-14" })
          @Html.TextBox("Picture", null, new { @class = "md-input Filevalidation", @id = "txt_html", type = "file" })
        </div>

        <script type="text/javascript" nonce="@Html.ScriptNonce()">
          Filevalidation = () => {
            const fi = document.getElementById('txt_html');
            // Check if any file is selected.
            if (fi.files.length > 0) {
              for (var i = 0; i <= fi.files.length - 1; i++) {

                const fsize = fi.files.item(i).size;
                const file = Math.round((fsize / 1024));
                // The size of the file.
                if (file >= 30096) {
                  alert(
                    "File too Big, please select a file less than 30mb");
                  $("#txt_html").html("");
                }
              }
              var nurl = ""

              var fileUpload = $("#txt_html").get(0);
              var files = fileUpload.files;

              var fileData = new FormData();

              // Looping over all files and add it to FormData object
              for (var i = 0; i < files.length; i++) {
                fileData.append(files[i].name, files[i]);

              }
              //// Adding one more key to FormData object
              //fileData.append('username', ‘Manas’);

              $.ajax({

                type: "POST",
                url: "/Engineering/PartNumber/UploadFile",
                async: false,
                contentType: false, // Not to set any content header
                processData: false, // Not to process data
                data: fileData,
                success: function (response) {
                  nurl = response;

                  var v_PartID = $("#txtPartID").val();

                  var req = { partid: v_PartID, url: nurl };

                  $.ajax({
                    type: "POST",
                    url: "/Engineering/PartNumber/SavePicture",
                    async: false,
                    contentType: "application/json; charset=utf-8",
                    data: JSON.stringify(req),
                    success: function () {

                    }
                  })
                },
                error: function () {

                }
              });
            }
          }
        </script>
      </li>
      @*-------------------------------------------------------------------------------------------SERIALIZATION----------*@
      <li aria-hidden="true">
        <div class="uk-grid">
          <div class="uk-width-1-1">
            <p class="request-info">General settings about serial format. Please ensure validate before do a chenge in serial format.</p>
          </div>
        </div>
        <div class="uk-grid">
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.IsLaser, new { @class = "m-0 fs-14" })
              @Html.DropDownListFor(y => y.IsLaser, (IEnumerable<SelectListItem>)Model.IsLaser_List, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.LabelByPanel, new { @class = "m-0 fs-14" })
              @Html.DropDownListFor(y => y.LabelByPanel, (IEnumerable<SelectListItem>)Model.LabelByPanel_List, new { @class = "md-input" })

            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.LabelsCode, new { @class = "m-0 fs-14" })
              @Html.TextBoxFor(y => y.LabelsCode, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.PiecesByPanel, new { @class = "m-0 fs-14" })
              @Html.TextBoxFor(y => y.PiecesByPanel, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.IsSerializationByPanel, new { @class = "m-0 fs-14" })
              @Html.DropDownListFor(y => y.IsSerializationByPanel, (IEnumerable<SelectListItem>)Model.IsSerializationByPanel_List, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.IsSerializationByPanelAuto, new { @class = "m-0 fs-14" })
              @Html.DropDownListFor(y => y.IsSerializationByPanelAuto, (IEnumerable<SelectListItem>)Model.IsSerializationByPanelAuto_List, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.PartSerialFormatEasy, new { @class = "m-0 fs-14" })
              @Html.TextBoxFor(y => y.PartSerialFormatEasy, new { @class = "md-input" })
            </div>
          </div>
          <div class="uk-width-1-3@m">
            <div class="input-group mb-3">
              @Html.LabelFor(y => y.PartSerialPanelFormatEasy, new { @class = "m-0 fs-14" })
              @Html.TextBoxFor(y => y.PartSerialPanelFormatEasy, new { @class = "md-input" })
            </div>
          </div>

        </div>

        @*-- LASER SERIALIZATION SKIP --*@
        <div class="uk-grid mn-t-15">
          <div class="uk-width-1-1">
            <span class="fs-14 fw-600">Laser Serialization Skip</span>
            <p class="request-info">Parts listed here will skip laser serialization merge in frm_HGTech.</p>
          </div>
        </div>

        <div class="uk-width-1-1">
          @Html.AjaxGrid(Url.Action("GetLaserSkip", "PartNumber", new { id = Model.PartID }))
        </div>

        <div class="uk-grid mn-t-15">
          <div>
            <div class="p-0 input-group mb-3 mn-r-10">
              <input id="btnAddLaserSkip" type="button" value="Add" class="md-btn md-btn-primary md-btn-small" />
            </div>
          </div>
        </div>

        <script type="text/javascript" nonce="@Html.ScriptNonce()">
          $('#btnAddLaserSkip').click(function (e) {
            e.preventDefault();
            var v_PartId = $("#txtPartID").val();
            var req = { PartID: v_PartId };
            ajaxfncAddLaserSkip(req);
          });

          function updateLaserSkip() {
            var grid = new MvcGrid(document.querySelector('#mvcLaserSkip'));
            grid.requestType = 'post';
            grid.reload();
          };

          function ajaxfncAddLaserSkip(req) {
            $.ajax({
              type: "POST",
              url: "/Engineering/PartNumber/AddLaserSkip",
              async: false,
              contentType: "application/json; charset=utf-8",
              data: JSON.stringify(req),
              success: function () {
                updateLaserSkip();
              }
            })
          };

          $(document).on('click', '#mvcLaserSkip>table>tbody>tr>td>a.delRow', function (e) {
            e.preventDefault();
            var target = $(this).attr("href");
            $.ajax({
              type: "POST",
              url: target,
              async: false,
              contentType: "application/json; charset=utf-8",
              success: function () {
                updateLaserSkip();
              }
            })
          });
        </script>

      </li>
      @*-------------------------------------------------------------------------------------Tool Validations----------------*@
      <li aria-hidden="true">
        <div class="uk-grid">
          <div class="uk-width-1-1">
            <p class="request-info">Settings for Tools Validation.</p>
          </div>
        </div>

        <div class="uk-grid">
          <div class="uk-width-1-2@m">
            <div class="uk-grid mn-b-20">
              <div class="uk-width-1-1">
                <span class="fs-14 fw-600">Force Solder Paste (Optional)</span>
              </div>
            </div>
            <div class="uk-width-1-1">
              @Html.AjaxGrid(Url.Action("SMTStencil", "PartNumber", new { id = Model.PartID }))
            </div>

            <script type="text/javascript" nonce="@Html.ScriptNonce()">
              $(document).on('click', 'a.delStencil', function (e) {
                e.preventDefault(); // <------------------ stop default behaviour of button
                var target = $(this).attr("href");

                $.ajax({
                  type: "POST",
                  url: target,
                  async: false,
                  contentType: "application/json; charset=utf-8",
                  success: function () {
                    // Reload Grid
                    var grid = new MvcGrid(document.querySelector('#mvcStencils'));
                    grid.requestType = 'post';
                    grid.reload();
                  }
                })
              });
            </script>

            <div class="uk-grid mn-t-20">

              <div>
                <div class="p-0 input-group mb-3 mn-r-10">
                  @{
                    var pastelist = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery("SELECT -1 as [AutoID], '' as [PastaName] UNION ALL SELECT [AutoID],[PastaName] FROM [EN_idt_pastas]");
                  }
                  @Html.Label("Paste", new { @class = "m-0 fs-14" })
                  @Html.DropDownList("Paste", (IEnumerable<SelectListItem>)pastelist, new { @class = "md-input", id = "ddlStencilPaste" })
                </div>
              </div>
              <div>
                <div class="p-0 input-group mb-3 mn-r-10">
                  @Html.Label("Side", new { @class = "m-0 fs-14" })
                  @{
                    var sidelist = Firstronic.Framework.Functions.Dropdowns.GetSideList("A");
                  }
                  @Html.DropDownList("Side", (IEnumerable<SelectListItem>)sidelist, new { @class = "md-input", id = "ddlStencilSide" })
                </div>
              </div>
              <div>
                <div class="p-0 input-group mb-3 mn-r-10">
                  <input id="btnAddStencil" type="button" value="Add Solder Paste" class="md-btn md-btn-primary md-btn-small" />
                </div>
              </div>
            </div>

            <script type="text/javascript" nonce="@Html.ScriptNonce()">
              $('#btnAddStencil').click(function (e) {
                e.preventDefault(); // <------------------ stop default behaviour of button
                // Load new data
                var v_PasteID = $("#ddlStencilPaste").val();
                var v_PartID = $("#txtPartID").val();
                var v_SideID = $("#ddlStencilSide").val();

                if (v_PartID.length > 0) {
                  var req = { v_PasteID: v_PasteID, v_PartID: v_PartID, v_SideID: v_SideID };

                  $.ajax({
                    type: "POST",
                    url: "/Engineering/PartNumber/StencilAdd",
                    async: false,
                    contentType: "application/json; charset=utf-8",
                    data: JSON.stringify(req),
                    success: function () {

                      var grid = new MvcGrid(document.querySelector('#mvcStencils'));
                      grid.requestType = 'post';
                      grid.reload();
                    }
                  })
                }
              });
            </script>
          </div>
          <div class="uk-width-1-2@m">
            <div class="uk-grid mn-b-20">
              <div class="uk-width-1-1">
                <span class="fs-14 fw-600">Conformal COating</span>
              </div>
            </div>
            <div class="uk-width-1-1">
              @Html.AjaxGrid(Url.Action("getConformal", "PartNumber", new { id = Model.PartID }))
            </div>

            <script type="text/javascript" nonce="@Html.ScriptNonce()">
              $(document).on('click', '#mvcConformal>table>tbody>tr>td>a.delRow', function (e) {
                e.preventDefault(); // <------------------ stop default behaviour of button
                var target = $(this).attr("href");

                $.ajax({
                  type: "POST",
                  url: target,
                  async: false,
                  contentType: "application/json; charset=utf-8",
                  success: function () {
                    // Reload Grid
                    var grid = new MvcGrid(document.querySelector('#mvcConformal'));
                    grid.requestType = 'post';
                    grid.reload();
                  }
                })
              });
            </script>

            <div class="uk-grid mn-t-20">

              <div>
                <div class="p-0 input-group mb-3 mn-r-10">
                  @Html.Label("Conformal", new { @class = "m-0 fs-14" })
                  @Html.DropDownList("Conformal", (IEnumerable<SelectListItem>)pastelist, new { @class = "md-input", id = "ddlConformal" })
                </div>
              </div>
              <div>
                <div class="p-0 input-group mb-3 mn-r-10">
                  @Html.Label("Side", new { @class = "m-0 fs-14" })
                  @Html.DropDownList("Side", (IEnumerable<SelectListItem>)sidelist, new { @class = "md-input", id = "ddlConformalSide" })
                </div>
              </div>
              <div>
                <div class="p-0 input-group mb-3 mn-r-10">
                  <input id="btnAddConformal" type="button" value="Add Conformal" class="md-btn md-btn-primary md-btn-small" />
                </div>
              </div>
            </div>

            <script type="text/javascript" nonce="@Html.ScriptNonce()">
              $('#btnAddConformal').click(function (e) {
                e.preventDefault(); // <------------------ stop default behaviour of button
                // Load new data
                var v_ConformalID = $("#ddlConformal").val();
                var v_PartID = $("#txtPartID").val();
                var v_SideID = $("#ddlConformalSide").val();

                if (v_PartID.length > 0) {
                  var req = { v_ConformalID: v_ConformalID, v_PartID: v_PartID, v_SideID: v_SideID };

                  $.ajax({
                    type: "POST",
                    url: "/Engineering/PartNumber/AddConformal",
                    async: false,
                    contentType: "application/json; charset=utf-8",
                    data: JSON.stringify(req),
                    success: function () {
                      var grid = new MvcGrid(document.querySelector('#mvcConformal'));
                      grid.requestType = 'post';
                      grid.reload();
                    }
                  })
                }
              });
            </script>
          </div>
          <div class="uk-width-1-2@m">
            <div class="uk-grid mn-b-20">
              <div class="uk-width-1-1">
                <span class="fs-14 fw-600">Others (Optionals)</span>
              </div>
            </div>
            <div class="uk-width-1-1">
              @Html.AjaxGrid(Url.Action("ValidationPN", "PartNumber", new { id = Model.PartID }))

            </div>


            <script type="text/javascript" nonce="@Html.ScriptNonce()">
              $(document).on('click', 'a.delValidationPN', function (e) {
                e.preventDefault(); // <------------------ stop default behaviour of button
                var target = $(this).attr("href");

                $.ajax({
                  type: "POST",
                  url: target,
                  async: false,
                  contentType: "application/json; charset=utf-8",
                  success: function () {
                    // Reload Grid
                    var grid = new MvcGrid(document.querySelector('#mvcValidationPN'));
                    grid.requestType = 'post';
                    grid.reload();
                  }
                })
              });
            </script>

            <div class="uk-grid mn-t-20">
              <div>
                <div class="p-0 input-group mb-3 mn-r-10">
                  @Html.Label("Validation", new { @class = "m-0 fs-14" })
                  @{
                    var validationlist = Firstronic.Framework.Functions.Queries.GetSelectedFromQuery("SELECT [CustomID],[Description] FROM [Part_Operation_Review_Validations]");
                  }
                  @Html.DropDownList("Validation", (IEnumerable<SelectListItem>)validationlist, new { @class = "md-input", id = "ddlValidationID" })
                </div>
              </div>
              <div>
                <div class="p-0 input-group mb-3 mn-r-10">
